-- Enrichment marathon batch: GlobaLeaks, GLPI, GlusterFS, GNUnet, GoAccess, goatcounter, GoCardless, GoCD

-- в”Ђв”Ђ GlobaLeaks в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$GlobaLeaks is a free, open-source platform that lets NGOs, newsrooms, companies and public bodies run secure, anonymous whistleblowing and reporting channels over Tor and HTTPS.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Italy$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Italian$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Portuguese$q$, $q$Arabic$q$, $q$Russian$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$GlobaLeaks Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$GlobaLeaks review 2026: how this open-source Tor-based whistleblowing platform works, its security model, pricing (its free), key features, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$GlobaLeaks is a free and open-source software platform purpose-built to let any organization, from small NGOs to national media outlets and public administrations, stand up a secure, anonymous whistleblowing and reporting channel without writing code. Rather than being a hosted SaaS product, GlobaLeaks is software you deploy yourself: it runs as a web application, typically exposed both over standard HTTPS and as a Tor Onion Service, so that a source can submit a tip, documents, or a message while remaining as anonymous as the underlying network allows. The project positions itself as infrastructure for accountability journalism, corporate compliance with anti-corruption and whistleblower-protection laws, and civil-society human-rights reporting, and it has been formally recognized as a Digital Public Good by the Digital Public Goods Alliance because of its transparent development model and privacy-first design. The idea for GlobaLeaks was conceived on 15 December 2010 by Fabio Pietrosanti and shared within the hacktivist and transparency-advocacy community; the first working prototype followed on 6 September 2011. Early core contributors included Arturo Filasto, Claudio Agosti, Giovanni Pellerano and Michele Orru, several of whom were already active in the Tor and digital-rights ecosystem. The project has been stewarded ever since by the Hermes Center for Transparency and Digital Human Rights, an Italian nonprofit organization dedicated to freedom of expression and digital civil liberties online, which continues to coordinate GlobaLeaks development, security audits and documentation as a community and grant-funded effort rather than a venture-backed company. Because GlobaLeaks has never taken equity investment, its funding history is a matter of public grant disclosure rather than Crunchbase-style financing rounds. In 2012 the GlobaLeaks 2.0 and companion Tor2web 3.0 releases were funded with roughly 108,400 US dollars under a Freedom2Connect-linked program. In 2014 the Hermes Center was awarded 200,000 euro from a foundation supporting the deployment of whistleblowing initiatives in the Global South, and later that year the Open Technology Fund committed approximately 234,000 US dollars to fund a GlobaLeaks development roadmap running from Q3 2014 through Q1 2016. The project publishes its funders and progress reports openly on its website as part of its transparency commitment, which mirrors the transparency it asks of the organizations that deploy it. Architecturally, GlobaLeaks is a Python-based backend paired with a browser-based frontend that an administrator configures through a setup wizard, defining reporting channels, recipient roles, and intake questionnaires without needing development skills. Security is central to the design: submissions and attachments are encrypted using the GlobaLeaks encryption protocol, communications between whistleblowers and recipients are end-to-end protected, and the platform enforces TLS 1.3 with an SSL Labs A+ configuration, including automatic certificate issuance and renewal through Let's Encrypt. Deployments are strongly encouraged to run as a Tor Onion Service (v3), since Tor's design resists selective interception and censorship far better than plain HTTPS, making it much harder for a network operator or state actor to identify or block a specific whistleblower. On the data-handling side, GlobaLeaks follows a strict minimization policy: it does not log source IP addresses, browser fingerprints, or device information, does not embed third-party trackers or persistent cookies, and is built to delete submission data as soon as retention policy allows rather than storing it indefinitely. Core features include configurable multi-step intake questionnaires, role-based recipient and reviewer workflows, secure two-way messaging between source and recipient without ever revealing the source's identity, file upload support for documents and evidence, multi-language interfaces spanning dozens of locales, granular administrative controls for defining multiple independent reporting channels within one instance, and audit logging for administrators that stops short of compromising source anonymity. Because it is open source software released without a commercial license, there is no pricing tier structure in the traditional SaaS sense: GlobaLeaks itself is free to download, self-host and modify under its open-source license, and the real cost to an adopting organization is server hosting, systems-administration time, and optionally paid implementation or hardening support from third-party consultancies or the Hermes Center's partner network, some of whom offer managed hosting for GlobaLeaks instances. The target audience spans investigative journalism outlets and media organizations that need SecureDrop-style leak channels, NGOs and human-rights groups operating in high-risk or authoritarian environments, and increasingly corporate compliance and ethics teams and public-sector bodies that must comply with whistleblower-protection regulation such as the EU Whistleblowing Directive, which requires many employers to provide a confidential reporting channel. Competitively, GlobaLeaks sits alongside SecureDrop as one of the two best-known open-source, security-audited whistleblowing platforms, but it differentiates itself with an admin-configurable multi-tenant model that lets one deployment serve multiple departments or reporting channels, a strong focus on ease of self-hosted setup via a guided wizard, and an explicit compliance angle aimed at organizations that need an auditable, GDPR-aligned reporting tool rather than only investigative-journalism leak drops. Its main trade-off versus commercial whistleblowing SaaS vendors such as EQS Integrity Line, Whistle, or NAVEX is that GlobaLeaks requires the adopting organization to own hosting, security patching and uptime themselves, in exchange for full data sovereignty, no vendor lock-in, and zero licensing cost.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3573cac7-ce24-4055-bf17-e0ce515e92a5';

