-- в”Ђв”Ђ GLPI в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$GLPI is an open-source IT asset management, helpdesk and service-desk platform used to track equipment, tickets, contracts and inventory across an organization.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted Community edition)$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$Spanish$q$, $q$German$q$, $q$Italian$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$GLPI Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$GLPI review 2026: how this open-source IT asset management and helpdesk platform works, its pricing tiers from Teclib, key features, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$GLPI, short for Gestionnaire Libre de Parc Informatique or Free IT Equipment Manager, is an open-source IT service management platform that combines IT asset management, a help desk and ticketing system, and inventory tracking in a single PHP-based application. Organizations use it to keep a live inventory of computers, servers, network devices, software licenses and other assets, to run an ITIL-aligned service desk for incidents and requests, and to manage contracts, warranties and knowledge-base articles tied to that inventory. The GLPI community project began in 2003 under the direction of the INDEPNET association, led by Jean-Mathieu Doleans, Julien Dombre and Bazile Lebeau, making it one of the longer-running open-source IT management tools still in active development more than two decades later. Teclib', a French company founded in 2011, began as an integrator building on top of GLPI starting in 2009, and in the summer of 2015 the GLPI community's leadership transferred roadmap management and development leadership to Teclib', which has served as the project's commercial editor and primary maintainer ever since. Teclib' is headquartered in France, with offices including one in the Paris region, and continues to fund core GLPI engineering through its commercial GLPI Network cloud and support offerings while keeping the underlying software open source under the GNU General Public License. Because GLPI has never taken outside venture funding, its business model is closer to a traditional open-core software publisher than a startup: revenue comes from subscriptions, hosting, and professional services rather than equity financing rounds. Technically, GLPI is a PHP web application backed by a relational database, and it is commonly paired with the separate GLPI Agent, a lightweight inventory agent that can be deployed across a fleet of endpoints to automatically discover hardware, software and network information and feed it back into the central GLPI instance. The platform exposes both a browser-based administrative console for IT teams and a self-service portal where end users can submit tickets, browse the knowledge base, and track request status. Its architecture is extensible through a large plugin ecosystem covering areas like advanced reporting, mobile device management, data centre and rack management, and integrations with monitoring and directory services such as LDAP and Active Directory. Core features include asset and configuration management (CMDB-style tracking of hardware, software, licenses and consumables), an ITIL-based service desk supporting incidents, problems, changes and service requests, contract and financial tracking tied to assets, a searchable knowledge base, project and task management modules, customizable dashboards and reporting, and role-based access control for multi-department or multi-site organizations. Recent commercial tiers have also begun layering in AI-assisted features and advanced dashboards at higher subscription levels. GLPI's pricing follows a freemium open-core structure. The core GLPI Community edition remains free and open source for organizations willing to self-host and self-support it. For organizations that want managed infrastructure or professional support, Teclib' sells GLPI Network cloud subscriptions priced per IT agent per month: a Public Cloud tier starts around 19 euro per agent per month with a minimum of one agent, unlimited assets and end users, 5 gigabytes of shared disk space, daily backups and automatic updates, while a Private Cloud tier runs around 21 euro per agent per month with a minimum of 25 agents, 50 gigabytes of dedicated disk space, hourly backups, a VPN tunnel and IP filtering. For teams that prefer to self-host but still want vendor support, Teclib' also sells self-hosted subscription tiers: a Basic plan around 100 euro per month for up to 10 IT agents and 500 assets, a Standard plan around 300 euro per month for up to 50 agents and 5,000 assets that adds standard plugins, AI features and an advanced dashboard, and an Advanced plan around 1,000 euro per month for 50-plus agents that unlocks the full plugin catalogue and mail-based approval workflows. GLPI's target audience spans small IT teams that just need free, self-hosted asset tracking, mid-size organizations that want managed cloud hosting with support, and larger enterprises or managed service providers that need multi-site, multi-tenant deployments with extensive plugin customization. Competitively, GLPI is most often compared with other open-source ITSM tools such as Snipe-IT for pure asset tracking or osTicket for pure help desk, as well as commercial ITSM suites like Freshservice, Jira Service Management and ServiceNow. Its differentiation is combining asset management and service desk in one open, self-hostable codebase with two decades of community maturity, a large plugin marketplace, and a French vendor offering both managed cloud and self-hosted commercial support paths, giving adopters a lower-cost, less vendor-locked alternative to the large proprietary ITSM platforms while still offering a paid support path for organizations that need it.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b4d4e26c-b174-4a6c-a897-123a9f5d759f';

