INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Tor Onion Service support$q$, $q$Deploy as a Tor v3 Onion Service alongside HTTPS so whistleblowers can submit reports with strong resistance to network-level identification or censorship.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$End-to-end encrypted submissions$q$, $q$Reports, file attachments and follow-up messages between source and recipient are encrypted using the GlobaLeaks encryption protocol.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Configurable intake questionnaires$q$, $q$Administrators build multi-step forms per reporting channel without writing code, tailoring the intake process to each department or use case.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Anonymous two-way messaging$q$, $q$Recipients can ask follow-up questions and sources can respond through a secure channel without ever revealing the source's real identity.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Multi-channel, multi-tenant setup$q$, $q$One GlobaLeaks instance can host several independent reporting channels for different departments, brands or programs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$No IP or metadata logging$q$, $q$The platform is built to avoid storing source IP addresses, device or browser fingerprints, and persistent cookies.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Automatic HTTPS with Let's Encrypt$q$, $q$TLS 1.3 certificates are provisioned and renewed automatically, giving deployments an SSL Labs A+ configuration out of the box.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Multi-language interface$q$, $q$The platform ships with translations covering dozens of languages for both administrators and reporting sources.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Free, open-source and fully self-hostable with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Strong, audited anonymity and encryption model built around Tor and TLS 1.3$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Flexible enough to serve journalism, NGO, and corporate compliance use cases from one codebase$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Transparent development and public funding disclosure build trust for high-risk deployments$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Recognized as a Digital Public Good, which helps with adoption by public-sector and NGO bodies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Requires the adopting organization to handle hosting, patching and uptime themselves$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$No official hosted or managed SaaS offering directly from the maintainers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Smaller ecosystem and commercial support network than proprietary whistleblowing platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Setup and hardening still require some systems-administration expertise to do safely$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Development pace depends on grant funding rather than predictable commercial revenue$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Is GlobaLeaks free to use?$q$, $q$Yes. GlobaLeaks is free, open-source software. There is no license fee; the only costs are the hosting infrastructure and administration time an organization spends running its own instance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Who maintains GlobaLeaks?$q$, $q$GlobaLeaks is developed and maintained by the Hermes Center for Transparency and Digital Human Rights, an Italian nonprofit, with funding from grants such as the Open Technology Fund rather than commercial investors.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Does GlobaLeaks require Tor to work?$q$, $q$No, but it supports and recommends running as a Tor Onion Service in addition to standard HTTPS access, since Tor offers stronger resistance to network-level identification and censorship for sensitive sources.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Is GlobaLeaks suitable for corporate whistleblower compliance, not just journalism?$q$, $q$Yes. Beyond investigative journalism, organizations use GlobaLeaks to meet whistleblower-protection regulations, such as the EU Whistleblowing Directive, by offering an internal, confidential reporting channel.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$What data does GlobaLeaks store about a whistleblower?$q$, $q$The platform is designed to avoid logging IP addresses, browser or device fingerprints, and persistent cookies, and it follows a strict data-retention policy that deletes submission data as soon as policy allows.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$How is GlobaLeaks different from SecureDrop?$q$, $q$Both are open-source, security-focused whistleblowing platforms, but GlobaLeaks emphasizes an admin-configurable, multi-channel model with a guided setup wizard, making it approachable for compliance and NGO deployments as well as journalism leak drops.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Investigative journalism leak channel$q$, $q$Newsrooms deploy GlobaLeaks as a secure digital dropbox so sources can share documents and tips anonymously over Tor.$q$, $q$Newsrooms and investigative journalists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Corporate whistleblower compliance$q$, $q$Companies stand up a confidential internal reporting channel to satisfy whistleblower-protection laws such as the EU Whistleblowing Directive.$q$, $q$Compliance and ethics teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Human-rights and anti-corruption reporting$q$, $q$NGOs operating in high-risk or authoritarian environments use GlobaLeaks to let witnesses and activists report abuses safely.$q$, $q$NGOs and civil-society organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$Community (self-hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full GlobaLeaks platform source code","Unlimited reporting channels","Tor Onion Service and HTTPS support","Community documentation and forums"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GlobaLeaks is free, open-source software for building secure and anonymous whistleblowing or reporting channels. Instead of signing up for a hosted service, an organization downloads and deploys the GlobaLeaks application on its own server or a partner's managed infrastructure, then configures reporting workflows through an administrative setup wizard.$q$, $q$The project was started in December 2010 by Fabio Pietrosanti and shared with the transparency and hacktivist community, with a first working prototype released in September 2011. It has since been developed and maintained by the Hermes Center for Transparency and Digital Human Rights, an Italian nonprofit, and is recognized by the Digital Public Goods Alliance as a Digital Public Good.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GlobaLeaks runs as a Tor Onion Service (v3) alongside standard HTTPS access, encrypts submissions and attachments end to end using its own encryption protocol, and enforces TLS 1.3 with automatic Let's Encrypt certificates. It deliberately avoids logging IP addresses, device fingerprints, or browser metadata, and does not embed third-party trackers or persistent cookies.$q$, $q$Administrators can define multiple independent reporting channels with custom intake questionnaires, assign recipients and reviewers by role, and communicate two-way with a source through secure messaging without ever learning that source's identity. The interface supports dozens of languages, making it usable for multinational NGOs, newsrooms and enterprises.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GlobaLeaks itself carries no license fee: it is free, open-source software that any organization can self-host, audit and modify. There is no SaaS subscription tier structure because GlobaLeaks is not sold as a hosted product by its maintainers.$q$, $q$The real cost of adoption is infrastructure and operations: server hosting, systems-administration time, and optionally paid implementation, hardening or managed-hosting support from third-party consultancies or partners in the Hermes Center's network.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3573cac7-ce24-4055-bf17-e0ce515e92a5', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$IT asset and configuration management$q$, $q$Tracks hardware, software licenses, network devices and consumables in a CMDB-style inventory with full lifecycle history.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Automated inventory with GLPI Agent$q$, $q$A lightweight companion agent discovers hardware, software and network details across endpoints and feeds them into the central inventory.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$ITIL-based service desk$q$, $q$Handles incidents, service requests, problems and changes with SLA tracking and a self-service portal for end users.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Contract and financial tracking$q$, $q$Links contracts, warranties and costs directly to the assets and departments they belong to.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Knowledge base$q$, $q$A searchable repository of articles that agents and end users can reference to resolve common issues.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Project and task management$q$, $q$Plans and tracks IT projects and tasks alongside day-to-day ticketing work.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Custom dashboards and reporting$q$, $q$Builds visual reports on ticket volume, asset status and SLA performance for IT management.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Plugin ecosystem$q$, $q$A large marketplace of community and official plugins extends GLPI into data-centre management, MDM, and deeper integrations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Free, open-source Community edition with no functional limit on self-hosting$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Combines asset management and service desk in one integrated platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Large, mature plugin ecosystem built over two decades$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Managed cloud and self-hosted paid tiers give a clear upgrade path for teams that outgrow self-support$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Strong ITIL alignment suits regulated or process-driven IT organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Interface can feel dated compared to newer, design-forward ITSM tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Self-hosted deployment requires PHP and database administration skills$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Advanced features like AI assistance and advanced dashboards are gated behind paid tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Plugin quality and maintenance varies since many are community-contributed$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Per-agent cloud pricing can add up quickly for larger IT estates$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Is GLPI free to use?$q$, $q$Yes, the core GLPI Community edition is free and open source under the GPL for organizations that self-host and self-support it. Paid tiers add managed cloud hosting, support and extra features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Who develops GLPI?$q$, $q$GLPI began in 2003 under the INDEPNET association and has been developed and commercially published by the French company Teclib' since it took over project leadership in 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$What is the GLPI Agent?$q$, $q$GLPI Agent is a separate, lightweight companion tool that automatically inventories hardware, software and network information on endpoints and reports it back to the central GLPI instance.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Can GLPI replace a dedicated help desk tool?$q$, $q$Yes, GLPI includes a full ITIL-aligned service desk module covering incidents, requests, problems and changes, so many organizations use it as both their asset system and their help desk.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Does GLPI support multiple languages?$q$, $q$Yes, GLPI ships with translations for numerous languages including English, French, Spanish, German, Italian and Portuguese.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$What is the difference between GLPI Network Cloud and self-hosted paid plans?$q$, $q$GLPI Network Cloud is a fully managed hosting subscription priced per IT agent, while the self-hosted paid tiers let you run GLPI on your own infrastructure while still getting Teclib' support and access to premium plugins.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$IT asset lifecycle tracking$q$, $q$IT teams maintain a live inventory of computers, servers, licenses and network gear from purchase through retirement.$q$, $q$IT operations and asset managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Internal help desk and service requests$q$, $q$Employees submit tickets through a self-service portal that IT staff triage and resolve using ITIL workflows.$q$, $q$IT support teams and end users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Managed service provider multi-client management$q$, $q$MSPs deploy GLPI to manage assets, tickets and contracts across multiple client organizations from one platform.$q$, $q$Managed service providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted, open-source core platform","Unlimited assets and end users","Community plugins and forums","Self-managed updates and support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$GLPI Network Public Cloud$q$, $q$From EUR 19/month per IT agent$q$, $q$Monthly, per agent (minimum 1 agent)$q$, NULL, $q$["Unlimited assets and end users","Level 3 support","5GB shared disk space","Daily backups and automatic updates"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$GLPI Network Private Cloud$q$, $q$From EUR 21/month per IT agent$q$, $q$Monthly, per agent (minimum 25 agents)$q$, NULL, $q$["Unlimited assets and end users","Dedicated resources, 50GB disk space","Hourly backups","VPN tunnel and IP filtering"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Self-Hosted Basic$q$, $q$From EUR 100/month$q$, $q$Monthly (up to 10 IT agents)$q$, NULL, $q$["500 assets, unlimited end users","1 production and 1 test instance","Community and basic plugins"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Self-Hosted Standard$q$, $q$From EUR 300/month$q$, $q$Monthly (up to 50 IT agents)$q$, NULL, $q$["5,000 assets, unlimited end users","2 production and 2 test instances","Standard plugins, AI features, advanced dashboard"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$Self-Hosted Advanced$q$, $q$From EUR 1,000/month$q$, $q$Monthly (50-plus IT agents)$q$, NULL, $q$["5,000-plus assets, unlimited end users","4 production and 4 test instances","All plugins included, mail-based approvals"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GLPI is an open-source IT asset management and service desk platform, combining hardware and software inventory tracking with an ITIL-based ticketing system. The project began in 2003 under the INDEPNET association and has been developed and commercially published by the French company Teclib' since 2015.$q$, $q$Teclib' keeps the core software open source under the GPL while monetizing through GLPI Network, a set of managed-cloud and self-hosted subscription tiers priced per IT agent, plus professional services and a plugin ecosystem.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GLPI tracks hardware, software licenses, network devices and consumables in a CMDB-style inventory, and pairs with the separate GLPI Agent to automatically discover assets across a fleet of endpoints. Its service desk covers incidents, requests, problems and changes in an ITIL-aligned workflow with a self-service portal for end users.$q$, $q$Additional modules cover contract and warranty tracking, a searchable knowledge base, project and task management, customizable dashboards, and role-based access for multi-site or multi-department organizations. A large plugin marketplace extends the platform into areas like data-centre and rack management, mobile device management, and advanced reporting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The GLPI Community edition is free and open source for self-hosted, self-supported use. Teclib' also sells GLPI Network managed-cloud tiers priced per IT agent per month, roughly 19 euro for Public Cloud (minimum one agent) and 21 euro for Private Cloud (minimum 25 agents), each with different backup, storage and networking allowances.$q$, $q$For teams that prefer to self-host with vendor support, self-hosted subscriptions start around 100 euro per month for a Basic tier (up to 10 agents, 500 assets), rising to roughly 300 euro per month for Standard (up to 50 agents, adds AI features and advanced dashboards) and around 1,000 euro per month for Advanced (50-plus agents, full plugin catalogue).$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b4d4e26c-b174-4a6c-a897-123a9f5d759f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$No centralized metadata server$q$, $q$Uses an elastic hashing algorithm to locate data across bricks, removing the single point of failure common in metadata-server architectures.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Scale-out capacity$q$, $q$Storage capacity and performance scale by adding new bricks or servers to a volume without downtime.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Replication and geo-replication$q$, $q$Data can be replicated across nodes for local redundancy and geo-replicated across sites for disaster recovery.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Multi-protocol access$q$, $q$Volumes can be accessed via the native GlusterFS client, NFS, or SMB, easing integration with existing infrastructure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Distributed and striped volumes$q$, $q$Files can be distributed or striped across bricks to balance capacity and throughput across the cluster.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Snapshotting$q$, $q$Supports point-in-time volume snapshots for backup and recovery workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Commodity hardware support$q$, $q$Runs on standard x86 servers over Ethernet or InfiniBand, avoiding proprietary SAN hardware requirements.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Open licensing$q$, $q$Licensed under GPLv3 with some components dual-licensed under GPLv2 or LGPLv3, allowing free use and modification.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Architecture without a centralized metadata server simplifies scaling$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Runs on commodity hardware, avoiding proprietary SAN costs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Mature codebase with over a decade of production use across many organizations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Flexible access via native client, NFS or SMB$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Red Hat ended commercial support and disbanded its engineering team at the end of 2024$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Upstream commit activity has dropped sharply, raising long-term maintenance concerns$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Several downstream projects have begun dropping GlusterFS integration support$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$No official enterprise support contract is currently available$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Newer alternatives like Ceph and Kubernetes-native storage systems are seeing far more active development$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Is GlusterFS still maintained?$q$, $q$Yes, but only through community effort. Red Hat ended commercial support for Red Hat Gluster Storage on 31 December 2024 and disbanded its engineering team, and upstream commit activity has fallen sharply since, though minor releases on the 10.x and 11.x lines continue.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Is GlusterFS free to use?$q$, $q$Yes, GlusterFS is free, open-source software licensed under GPLv3 with some components dual-licensed under GPLv2 or LGPLv3. There is no cost to download, deploy or modify it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Who created GlusterFS?$q$, $q$GlusterFS was created in 2005 by Gluster Inc., founded by Anand Babu Periasamy, who wrote the initial version. Red Hat acquired Gluster in October 2011 for a reported 136 million US dollars.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$What is the difference between GlusterFS and Red Hat Gluster Storage?$q$, $q$GlusterFS is the open-source upstream project. Red Hat Gluster Storage was Red Hat's commercially supported distribution built on GlusterFS, but that commercial product's support lifecycle ended in December 2024.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Should I still deploy new GlusterFS clusters in 2026?$q$, $q$Many teams now evaluate alternatives such as Ceph or Kubernetes-native storage systems for new deployments given GlusterFS's reduced development pace, though existing GlusterFS users continue running it in production.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Does GlusterFS require a centralized metadata server?$q$, $q$No. GlusterFS uses an elastic hashing algorithm to locate data across storage bricks instead of a centralized metadata server, which avoids that architecture's single point of failure.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Scale-out storage for existing production clusters$q$, $q$Organizations already running GlusterFS continue to expand capacity by adding bricks to existing volumes.$q$, $q$Sysadmins operating legacy Gluster clusters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Homelab and cost-sensitive distributed storage$q$, $q$Hobbyists and small teams build distributed file storage on commodity hardware without licensing fees.$q$, $q$Homelab operators and small IT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Content delivery and streaming media storage$q$, $q$Media platforms historically used GlusterFS to store and serve large volumes of streaming content across distributed nodes.$q$, $q$Media and content delivery operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full GlusterFS source and binaries","Unlimited cluster size","Community mailing lists and GitHub support","GPLv3 / GPLv2 / LGPLv3 licensed components"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GlusterFS is an open-source, scale-out distributed file system that pools storage from multiple commodity servers into a single large network file system, accessible over Ethernet or InfiniBand. It was created in 2005 by Gluster Inc., founded by Anand Babu Periasamy, and was acquired by Red Hat in October 2011 for a reported 136 million US dollars.$q$, $q$Red Hat sold it commercially as Red Hat Storage Server and later Red Hat Gluster Storage, but ended commercial support and disbanded its Gluster engineering team at the close of 2024. The project continues under reduced community maintenance rather than active corporate development.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GlusterFS has no centralized metadata server; it uses an elastic hashing algorithm to locate files across storage bricks, avoiding a single point of failure or metadata bottleneck as the cluster scales. Capacity is added simply by attaching new bricks to a volume.$q$, $q$The system supports replication for redundancy, geo-replication for cross-site disaster recovery, striping and distribution of files across nodes, snapshotting, and access via its native client, NFS, or SMB for compatibility with existing tooling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GlusterFS is free, open-source software licensed primarily under GPLv3, with some components dual-licensed under GPLv2 or LGPLv3. There is no license fee to download, deploy or modify it.$q$, $q$Since Red Hat wound down its commercial Red Hat Gluster Storage product and support offering at the end of 2024, there is no official paid enterprise tier; adopters rely on community support channels and bear only their own hardware and administration costs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8bdbdb20-3a53-4c65-b774-2c8bcceae403', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Encrypted peer-to-peer overlay network$q$, $q$Provides an authenticated, encrypted transport layer between peers that avoids centralized servers or trusted intermediaries.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$CADET secure channels$q$, $q$Establishes end-to-end encrypted communication channels between peers, usable for chat, file transfer or custom applications.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Censorship-resistant file sharing$q$, $q$Lets publishers share files anonymously with a configurable trade-off between anonymity and performance.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$GNU Name System (GNS)$q$, $q$A fully decentralized, censorship-resistant replacement for DNS built on a directed graph of delegations instead of a central root.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$R5N distributed routing$q$, $q$An overlay routing and distributed hash table mechanism designed to resist traffic analysis across the peer network.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$VPN application$q$, $q$Provides virtual private networking functionality built on top of GNUnet's secure transport layer.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Modular application framework$q$, $q$Exposes generic building blocks so developers can build custom secure, decentralized applications on the GNUnet stack.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Cross-platform free software$q$, $q$Distributed as free software that can be compiled and run on common Unix-like systems at no cost.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Genuinely decentralized architecture with no reliance on trusted central servers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$GNU Name System offers query privacy that traditional DNS cannot provide$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Modular framework lets developers build custom secure peer-to-peer applications$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Backed by two decades of academic networking and cryptography research$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Steep learning curve aimed more at developers and researchers than end users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Some subsystems, including CADET and file sharing, have known performance and usability limitations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Smaller user base and network effect compared to Tor or IPFS$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Documentation and tooling are less polished than commercial privacy products$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$No commercial support option for organizations that need guaranteed SLAs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Is GNUnet free to use?$q$, $q$Yes, GNUnet is entirely free, open-source software distributed as a GNU package with no licensing fee or commercial tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$How is GNUnet different from Tor?$q$, $q$Tor focuses on anonymous routing for existing internet traffic through a network of relays, while GNUnet aims to be a broader peer-to-peer application framework covering encrypted transport, file sharing, messaging and decentralized naming from the ground up.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$What is the GNU Name System?$q$, $q$The GNU Name System (GNS) is GNUnet's decentralized alternative to DNS, replacing the centralized DNS hierarchy with a directed graph of user delegations and cryptographically secured, private queries.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Who maintains GNUnet?$q$, $q$GNUnet has been developed primarily under Christian Grothoff's leadership since it became an official GNU package in 2002, with contributions from volunteers, academic researchers and grant-funded developers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Is GNUnet ready for non-technical end users?$q$, $q$Not really. GNUnet is aimed more at developers, researchers and technically sophisticated users building or running peer-to-peer applications, and some subsystems still have known performance limitations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Can I build my own application on top of GNUnet?$q$, $q$Yes, GNUnet is designed as a modular framework with generic building blocks such as CADET for secure channels, so developers can build custom decentralized applications on top of the existing protocol stack.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Censorship-resistant file sharing$q$, $q$Users publish and retrieve files anonymously through GNUnet's peer-to-peer file-sharing application in environments with network censorship.$q$, $q$Privacy advocates and users in censored regions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Decentralized naming for applications$q$, $q$Developers use the GNU Name System to resolve names without depending on centralized DNS infrastructure.$q$, $q$Developers building decentralized applications$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Academic and research networking projects$q$, $q$Researchers use GNUnet as a testbed and framework for studying secure, decentralized networking protocols.$q$, $q$Computer science researchers and academics$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full GNUnet source code and packages","CADET, file sharing, VPN and GNS applications","Community mailing lists and documentation","GNU project support and governance"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GNUnet is a free software framework for secure, decentralized peer-to-peer networking that avoids centralized or trusted intermediaries. It became an official GNU package on 17 February 2002 and has been developed primarily by Christian Grothoff, growing from an original focus on anonymous file sharing into a broader protocol stack for building privacy-preserving applications.$q$, $q$As a GNU project, GNUnet has no commercial ownership history; it is developed by volunteers, academics and grant-funded contributors, with support from organizations such as NLnet, and gained renewed interest after the 2013 PRISM surveillance revelations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The CADET subsystem provides secure, end-to-end encrypted channels between peers on GNUnet's overlay network, with routing designed to resist traffic analysis via mechanisms such as its R5N distributed hash table. On top of this, GNUnet ships censorship-resistant file sharing that lets publishers trade off anonymity against performance, plus support for non-anonymous file sharing when speed matters more.$q$, $q$The GNU Name System (GNS) is a fully decentralized alternative to DNS that uses a directed graph of delegations instead of a central root, with cryptographically secured queries and responses so that even relaying peers cannot easily see what is being looked up.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GNUnet is entirely free and open-source software with no commercial licensing tier. Anyone can download the source or pre-built packages and run a full peer at no cost.$q$, $q$There is no paid enterprise support offering; the project's documentation, mailing lists and community channels serve as the primary support path for users and developers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('685a2454-07f3-45db-9fc9-03a9a78f0a9b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Real-time terminal dashboard$q$, $q$A curses-based interface shows live-updating traffic statistics directly over an SSH session with no browser required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Self-contained HTML reports$q$, $q$Generates a single HTML file with embedded charts that can optionally live-update over WebSocket from a running GoAccess process.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Broad log format support$q$, $q$Parses standard formats from Apache, Nginx, Amazon S3 and CloudFront, plus custom formats via configurable format strings.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$IP geolocation$q$, $q$Resolves visitor country and city when paired with a MaxMind GeoIP database for geographic traffic breakdowns.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Compressed and combined log reading$q$, $q$Reads gzip-compressed logs directly and can combine multiple log files into a single analysis session.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$No database or tracking script required$q$, $q$Processes existing server logs directly with no database, background daemon, or client-side JavaScript tracker needed.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Bot and visitor filtering$q$, $q$Distinguishes automated bot traffic from genuine visitors to give cleaner traffic statistics.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$JSON export$q$, $q$Outputs parsed statistics as JSON for integration into other monitoring or reporting pipelines.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Completely free and open source with no paid tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Lightweight C implementation that processes even large log files quickly$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$No JavaScript tracking script or third-party data sharing required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Works both as a live terminal dashboard and a shareable HTML report$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Simple installation via standard package managers on Linux and macOS$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Requires shell or server access to logs, unlike hosted analytics dashboards$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Terminal interface has a learning curve for non-technical users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$No built-in team collaboration, sharing, or user-management features$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Geolocation requires a separate MaxMind GeoIP database to be configured$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Single maintainer-driven project means slower response to some feature requests$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Is GoAccess free to use?$q$, $q$Yes, GoAccess is free, open-source software with no commercial edition or subscription tier. It can be installed at no cost via most package managers or compiled from source.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Does GoAccess require a JavaScript tracking snippet?$q$, $q$No. GoAccess works entirely by parsing existing web server log files, so it requires no client-side JavaScript tracker on the website being analyzed.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Can GoAccess show real-time traffic?$q$, $q$Yes, GoAccess can run in real-time mode, continuously updating its terminal dashboard or HTML report as new lines are appended to the log file it is watching.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$What log formats does GoAccess support?$q$, $q$GoAccess supports common formats from Apache and Nginx as well as Amazon S3 and CloudFront logs, and it also supports fully custom log formats via configurable format strings.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Who created GoAccess?$q$, $q$GoAccess was created by Gerardo Orellana, who published its first version in July 2010, and it has remained a community-maintained open-source project since.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Can I view GoAccess reports in a web browser?$q$, $q$Yes, GoAccess can generate a self-contained HTML report with charts, and that report can optionally connect over WebSocket to a running GoAccess process for live updates in the browser.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Quick server traffic diagnostics$q$, $q$System administrators point GoAccess at a live access log to instantly see traffic patterns, top pages and error rates.$q$, $q$System administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Privacy-respecting site analytics$q$, $q$Website operators who want traffic insight without adding a JavaScript tracker use GoAccess to analyze existing server logs.$q$, $q$Privacy-conscious website operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Incident and outage investigation$q$, $q$DevOps and SRE teams use GoAccess's real-time dashboard to spot traffic spikes or error surges during an incident.$q$, $q$DevOps and SRE teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full GoAccess source code and binaries","Terminal and HTML report modes","Real-time log monitoring","Community support via GitHub and mailing list"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GoAccess is a free, open-source, real-time web log analyzer that runs as a terminal dashboard or generates a self-contained HTML report. Created by Gerardo Orellana, who published its first version in July 2010, it has remained a community-maintained project with no corporate ownership, funding rounds or commercial edition.$q$, $q$Written in C and dependent on very few libraries, most notably ncurses, GoAccess parses logs from web servers and cloud services including Apache, Nginx, Amazon S3 and CloudFront, processing them entirely on infrastructure the operator already controls.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$In terminal mode, GoAccess presents a curses-based dashboard with panels for unique visitors, requested files, referrers, 404 errors, operating systems, browsers and geographic location, all navigable over SSH with keyboard shortcuts. In HTML mode, it generates a single self-contained report that can connect over WebSocket to a running process for live-updating charts in a browser.$q$, $q$It supports custom log formats via configurable format strings, reading compressed or multiple combined log files, IP geolocation when paired with a MaxMind GeoIP database, visitor and bot filtering, and JSON export for piping parsed data into other tooling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GoAccess is free, open-source software with no commercial edition, subscription tier, or hosted SaaS product. It can be installed via most Linux package managers, Homebrew on macOS, or compiled from source at no cost.$q$, $q$Support is community-driven through the project's GitHub repository, mailing list and documentation rather than a paid support contract, since there is no company behind GoAccess selling enterprise plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a432f190-1b4c-4ed3-8f70-e63c936ac1f0', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Cookieless visitor tracking$q$, $q$Computes unique visits without cookies or persistent identifiers, avoiding the personal-data tracking that typically triggers consent requirements.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Lightweight JavaScript snippet$q$, $q$Adds roughly 3.5 kilobytes of tracking code to a page, keeping page-load impact minimal.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$JavaScript-free pixel tracking$q$, $q$Offers a tracking-pixel option for sites that cannot or prefer not to run JavaScript.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Single Go binary self-hosting$q$, $q$Ships as one self-contained binary written in Go, making self-hosted deployment straightforward without a separate database server.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Accessible dashboard$q$, $q$Built to work with screen readers and keyboard navigation, reflecting its creator's accessibility-first design philosophy.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Campaign and referrer tracking$q$, $q$Tracks referral sources and UTM campaign parameters to show where traffic originates.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Data export and portability$q$, $q$Lets users export all collected data at any time and cancel their account without losing access to their own data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Log file import$q$, $q$Supports importing historical traffic data directly from existing server log files.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Free for personal and small-business non-commercial use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$No cookies or persistent identifiers, simplifying GDPR compliance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Extremely simple self-hosting as a single Go binary$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Strong accessibility focus with a screen-reader-friendly dashboard$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Permissive EUPL license allows self-hosting and even commercial forking$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Free hosted tier usage limits are loosely defined rather than a fixed numeric quota$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Single-developer project may have slower support response than larger vendor teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Fewer advanced segmentation and funnel-analysis features than full-scale analytics suites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Self-hosting still requires basic server administration knowledge$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Smaller ecosystem of integrations compared to Google Analytics$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Is GoatCounter free?$q$, $q$Yes, the hosted goatcounter.com service is free for reasonable public and non-commercial usage, and the self-hosted open-source version is always free with no usage ceiling.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Does GoatCounter use cookies?$q$, $q$No, GoatCounter does not use cookies or assign persistent unique identifiers to visitors, which is why most sites can run it without a cookie-consent banner under GDPR.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Can I self-host GoatCounter?$q$, $q$Yes, GoatCounter is open source and distributed as a single, self-contained Go binary, making self-hosting straightforward without needing a separate database server.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Who created GoatCounter?$q$, $q$GoatCounter was created by developer Martin Tournoij, known online as arp242, with the hosted service launching in August 2019.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$What license is GoatCounter released under?$q$, $q$GoatCounter is released under the European Union Public License version 1.2, which permits self-hosting, modification and even commercial forking under the same license terms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$How does GoatCounter compare to Google Analytics?$q$, $q$GoatCounter is much lighter weight, does not track personal data or use cookies, and is open source, but it offers fewer advanced segmentation and funnel-analysis features than Google Analytics.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Privacy-friendly blog and personal site analytics$q$, $q$Independent bloggers track page views and referrers without adopting Google Analytics or a cookie-consent banner.$q$, $q$Bloggers and personal website owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$GDPR-friendly small business analytics$q$, $q$Small businesses get essential traffic insight while minimizing legal and compliance overhead around visitor tracking.$q$, $q$Small business website owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Self-hosted analytics for developers$q$, $q$Developers deploy the single Go binary on their own infrastructure for full data control and no third-party dependency.$q$, $q$Developers and privacy-focused organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Hosted Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Reasonable public and non-commercial usage","Page views, referrers, campaigns","Cookieless, GDPR-friendly tracking","Data export and account cancellation anytime"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source codebase (EUPL-1.2)","Single Go binary deployment","No usage ceiling","Full data ownership on your own infrastructure"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GoatCounter is an open-source, privacy-focused web analytics platform created by developer Martin Tournoij, who publishes as arp242. The hosted goatcounter.com service launched in August 2019 as a single-developer project with no outside investors, funded through hosted-service revenue and GitHub Sponsors.$q$, $q$It is built as a single, self-contained binary written in Go, making self-hosting unusually simple, while the hosted version offers the same software as a managed service for users who do not want to run their own server.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GoatCounter avoids cookies and persistent unique identifiers, computing unique visits through short-lived, privacy-respecting session heuristics instead, which lets most sites run it without a cookie-consent banner under GDPR. Integration options include a roughly 3.5 kilobyte JavaScript snippet, a JavaScript-free tracking pixel, backend middleware, or bulk log-file import.$q$, $q$The dashboard surfaces page views, unique visits, referrers, campaign and UTM tracking, browser and screen-size breakdowns, and visitor country and language, and it is deliberately built to be usable with screen readers and keyboard navigation, reflecting the creator's accessibility focus. Users can export all their data at any time and cancel without lock-in.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The hosted goatcounter.com service is free for reasonable public and non-commercial usage, covering personal websites and small-to-medium businesses. Sites with very high traffic volumes or larger commercial usage are asked to contribute through GitHub Sponsors to help cover shared hosting costs.$q$, $q$The self-hosted option is completely free with no usage ceiling, since it uses the same open-source codebase distributed under the European Union Public License version 1.2, which is permissive enough to allow a self-hosted deployment to be modified and even shipped as a commercial fork under the same license.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a134f9f9-ee6d-4f7d-9d03-413bbcf4e3ec', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Multi-country direct debit coverage$q$, $q$Connects to direct debit and bank-payment schemes including Bacs (UK), SEPA (eurozone), ACH (US) and BECS (Australia) through one API.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Success+ payment recovery$q$, $q$Uses machine learning to automatically retry failed recurring payments, aiming to recover a large share of otherwise-lost revenue.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Protect+ fraud protection$q$, $q$Adds fraud detection and chargeback-challenge support for businesses on the Pro plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Customizable hosted checkout$q$, $q$Lets businesses embed a branded, customizable payment collection flow into their signup or billing process.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$350-plus pre-built integrations$q$, $q$Connects out of the box with accounting, CRM and billing platforms such as Xero, QuickBooks, Salesforce and Zoho.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$One-off, subscription and instalment billing$q$, $q$Supports single payments, recurring subscriptions, membership dues and instalment plans within one platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Open banking instant bank payments$q$, $q$Offers account-to-account instant bank payment options in supported markets alongside traditional direct debit.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Webhooks and developer API$q$, $q$Exposes a full API and webhook system for developers to build custom billing and payment workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Lower failure and chargeback rates than card payments for recurring billing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Broad coverage across 40-plus countries through one integration$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Automated payment recovery (Success+) can meaningfully reduce failed-payment revenue loss$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$No setup or monthly fees on standard plans$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Large library of pre-built accounting and CRM integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Transaction fees scale with plan tier, and advanced fraud and recovery features cost more$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$International transaction fees are notably higher than domestic ones$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Custom checkout and bank-statement branding cost extra on top of transaction fees$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Direct debit payments settle more slowly than card payments in some markets$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Pending acquisition by Mollie introduces uncertainty around future branding and roadmap$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$How much does GoCardless charge per transaction?$q$, $q$The Standard plan charges 1 percent plus 20 pence per domestic UK transaction, capped at 4 pounds, with higher percentages and caps on the Advanced and Pro tiers, which add payment recovery and fraud protection features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Who founded GoCardless?$q$, $q$GoCardless was founded in 2011 by Hiroki Takeuchi, Matt Robinson and Tom Blomfield, who were Oxford University students when they secured initial funding from Y Combinator.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Is GoCardless being acquired?$q$, $q$In December 2025, Dutch payments company Mollie announced an agreement to acquire GoCardless for approximately 1.05 billion euro in a mostly stock-based deal, forming a combined payments group valued at roughly 3 billion euro.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$What payment methods does GoCardless support?$q$, $q$GoCardless primarily supports direct debit schemes such as Bacs, SEPA, ACH and BECS across 40-plus countries, along with card payments and open-banking instant bank payments in some regions.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$What is Success+ on GoCardless?$q$, $q$Success+ is GoCardless's machine-learning-driven payment recovery feature, available on the Advanced and Pro plans, that automatically retries failed recurring payments to recapture revenue.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Does GoCardless charge setup or monthly fees?$q$, $q$No, GoCardless states there are no setup costs or hidden fees on its standard plans; businesses pay per-transaction fees instead.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Subscription and SaaS billing$q$, $q$Software companies collect recurring subscription payments via direct debit to reduce card-failure churn.$q$, $q$SaaS and subscription businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Membership and subscription-box billing$q$, $q$Membership organizations and subscription-box services automate recurring dues collection across multiple countries.$q$, $q$Membership and subscription commerce businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$B2B invoicing and instalment billing$q$, $q$B2B billing platforms collect one-off invoices and instalment payments directly from customer bank accounts.$q$, $q$B2B billing and finance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Standard$q$, $q$1% + 20p per transaction (capped at GBP 4)$q$, $q$Per transaction$q$, NULL, $q$["One-off, subscription, membership and instalment payments","40-plus country coverage","350-plus integrations","24/7 support, no setup fees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Advanced$q$, $q$1.25% + 20p per transaction (capped at GBP 5)$q$, $q$Per transaction$q$, NULL, $q$["Everything in Standard","Success+ automatic payment recovery","Enhanced identity verification"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Pro$q$, $q$1.4% + 20p per transaction (capped at GBP 5.60)$q$, $q$Per transaction$q$, NULL, $q$["Everything in Advanced","Protect+ fraud detection","Chargeback challenge support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$Custom$q$, $q$Custom pricing$q$, $q$Negotiated$q$, NULL, $q$["For businesses with GBP 1m-plus annual revenue","Volume discounts","Dedicated account support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GoCardless is a London-headquartered fintech platform built around collecting recurring and one-off payments directly from customer bank accounts, most notably via direct debit, rather than relying solely on card networks. It was founded in 2011 by Hiroki Takeuchi, Matt Robinson and Tom Blomfield, Oxford University students who secured 150,000 US dollars from Y Combinator within hours of their initial pitch.$q$, $q$The company raised well-known rounds over the following decade, including a 2022 Series G of 312 million US dollars led by Permira, and in December 2025 Dutch payments company Mollie announced an agreement to acquire GoCardless for approximately 1.05 billion euro, forming a combined payments group valued at roughly 3 billion euro.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GoCardless connects businesses to direct debit and bank-payment schemes across the UK, eurozone, United States, Australia and other markets through a single API integration, alongside card payments and open-banking instant bank payments in some regions. Its Success+ feature uses machine learning to automatically retry and recover failed recurring payments, while Protect+ adds fraud detection and chargeback-challenge support on higher tiers.$q$, $q$The platform supports one-off, subscription, membership and instalment payment collection, offers a customizable hosted checkout, and connects to more than 350 pre-built integrations with accounting, CRM and billing tools such as Xero, QuickBooks and Salesforce.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GoCardless charges per-transaction fees rather than a flat subscription, across four tiers. Standard costs 1 percent plus 20 pence per domestic transaction (capped at 4 pounds); Advanced costs 1.25 percent plus 20 pence (capped at 5 pounds) and adds Success+ payment recovery; Pro costs 1.4 percent plus 20 pence (capped at 5.60 pounds) and adds Protect+ fraud protection.$q$, $q$International transactions cost roughly double the domestic percentage across all tiers, and payments over 2,000 pounds add a 0.3 percent surcharge. Businesses processing over 1 million pounds annually can access a negotiated Custom plan, and optional add-ons include custom bank-statement branding and a fully customized checkout.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('44e76fa8-8fba-447b-a227-c3bb42e2b74f', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Value-stream map visualization$q$, $q$Shows the entire path from code commit to production deployment in a single visual view, built into the core product.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Complex pipeline modeling$q$, $q$Supports parallel execution and fan-in and fan-out dependency management for intricate multi-stage release processes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Cross-build traceability$q$, $q$Lets teams compare files, artifacts and commit messages across any two arbitrary builds for debugging and audits.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Cloud-native deployment support$q$, $q$Integrates with Kubernetes, Docker and AWS for deploying pipeline agents in modern cloud environments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Extensible plugin architecture$q$, $q$Supports official and community plugins for source control, artifact storage, authentication and notifications, plus custom plugin development.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Agent-based execution model$q$, $q$Distributes pipeline stage execution across one or more agent processes coordinated by a central GoCD server.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Built-in core functionality$q$, $q$Value-stream visualization, workflow modeling and traceability work out of the box without requiring plugins.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Apache 2.0 open-source licensing$q$, $q$Fully open-source under a permissive license, allowing free use, modification and redistribution.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Completely free and open source with no commercial licensing tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Value-stream map gives a uniquely clear view of the entire path to production$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Strong native support for complex, multi-stage pipeline dependencies$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Deep build-to-build traceability for debugging and auditing releases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Core CD functionality works without needing heavy plugin stacking$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$No organizational backing or commercial support since January 2021$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Smaller plugin and integration ecosystem than Jenkins, GitLab CI/CD or GitHub Actions$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Development pace has slowed considerably compared to actively funded CI/CD competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Requires self-hosting and infrastructure management with no managed cloud offering$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Smaller community and fewer learning resources than more popular CI/CD tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Is GoCD free to use?$q$, $q$Yes, GoCD is completely free and open-source software licensed under Apache 2.0, with no commercial tier or subscription fee.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Who created GoCD?$q$, $q$GoCD originated at Thoughtworks Studios in 2007 as a commercial product named Cruise, an evolution of the CruiseControl continuous integration server, and was renamed GoCD around 2010 before being open-sourced in February 2014.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Is GoCD still actively developed?$q$, $q$GoCD has had no dedicated organizational backing or commercial support since January 2021, and it continues today as a community-maintained project sponsored by Thoughtworks rather than an actively funded product.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$What makes GoCD different from Jenkins?$q$, $q$GoCD's built-in value-stream map and native complex pipeline modeling and cross-build traceability come out of the box, whereas Jenkins typically relies on a much larger plugin ecosystem to achieve comparable pipeline visualization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Does GoCD support Kubernetes and Docker?$q$, $q$Yes, GoCD integrates with Kubernetes, Docker and AWS, letting teams run pipeline agents and deployments in cloud-native and containerized environments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Does GoCD offer a hosted or managed version?$q$, $q$No, GoCD is only available as self-hosted, open-source software; there is no official managed cloud offering from Thoughtworks.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Complex multi-service release pipelines$q$, $q$Teams with intricate dependency chains between services use GoCD's value-stream map and pipeline modeling to visualize and manage releases.$q$, $q$Platform and release engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Cloud-native continuous delivery$q$, $q$Organizations deploy GoCD agents into Kubernetes and Docker environments to run containerized build and deployment pipelines.$q$, $q$DevOps teams running cloud-native infrastructure$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Build and release traceability for audits$q$, $q$Regulated teams use GoCD's build comparison and traceability features to track exactly what changed between any two releases.$q$, $q$Teams with compliance or audit requirements$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full GoCD server and agent software","Value-stream map visualization","Unlimited pipelines and agents","Community support via GitHub and forums"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GoCD is a free, open-source continuous delivery server used to model and run complex build, test and deployment pipelines. It originated at Thoughtworks Studios in 2007 as a commercial product named Cruise, an evolution of the earlier CruiseControl continuous integration server, and was renamed GoCD around 2010.$q$, $q$Thoughtworks open-sourced GoCD under the Apache License, Version 2.0 on 25 February 2014. Since January 2021, the project has had no dedicated organizational backing or commercial support offering, continuing purely as a community-maintained project sponsored by Thoughtworks.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GoCD's signature feature is its value-stream map, a single visual representation of the entire path from a code commit through every build, test and deployment stage to production. Pipeline modeling supports parallel execution and complex fan-in and fan-out dependency management, all built in rather than requiring heavy plugin stacking.$q$, $q$The platform provides traceability that lets teams compare files, artifacts and commit messages across any two arbitrary builds, integrates with Kubernetes, Docker and AWS for cloud-native deployment, and supports an extensible plugin architecture for source control, artifact storage, authentication and notifications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GoCD is entirely free and open-source, licensed under Apache 2.0, with no commercial tier or paid subscription. Teams download the server and agent binaries or container images and run them on their own infrastructure at no cost.$q$, $q$There is no paid support contract available, since Thoughtworks no longer offers commercial support for GoCD; users rely on community documentation, GitHub issues and forums instead.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('74b2d4e2-99dc-4bc1-bfaa-f10e06aac809', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
